import base64
import hashlib
import os

import pytest


def pytest_sessionstart(session):
    required = os.environ.get('ATOMIC_REQUIRE_CUDA_TESTS', '').strip().lower()
    if required not in {'1', 'true', 'yes', 'on'}:
        return

    import torch
    import feature_transformer

    missing = []
    if not torch.cuda.is_available():
        missing.append('a usable torch CUDA device')
    if feature_transformer.cp is None:
        missing.append('a matching CuPy installation')
    if missing:
        raise pytest.UsageError(
            'ATOMIC_REQUIRE_CUDA_TESTS=1 requires ' + ' and '.join(missing)
        )


# Deterministic 32-record Atomic legacy fixture (32 * 72 bytes), generated by
# the pinned Fairy-Stockfish data generator. Keeping it encoded as text avoids
# platform-dependent binary patches while preserving the exact old ABI.
ATOMIC_LEGACY_32_B64 = """

"""


@pytest.fixture
def atomic_legacy_32(tmp_path):
    data = base64.b64decode(ATOMIC_LEGACY_32_B64)
    assert len(data) == 32 * 72
    assert hashlib.sha256(data).hexdigest() == '9749b7673746e51177327081b8982a7962e4f7fbeb80561f69dd16c953970b91'
    path = tmp_path / 'atomic-legacy-32.bin'
    path.write_bytes(data)
    return path
